<?php
require_once __DIR__.'/functions.php';$member=require_member();$stmt=db()->prepare("SELECT id,titulo,slug,status,fecha FROM posts WHERE member_author_id=? AND post_type='community' ORDER BY fecha DESC");$stmt->execute([$member['id']]);$posts=$stmt->fetchAll();render_header('Mis publicaciones',['robots'=>'noindex,nofollow']);?><section class="panel"><div class="moderation-title"><div><h1>Mis publicaciones</h1><p class="muted">Crea, edita o elimina tus temas.</p></div><a class="button" href="/community-write.php">Nueva publicación</a></div><?php foreach($posts as $post):?><article class="user-card"><div class="user-card-head"><div><strong><?=e($post['titulo'])?></strong><small><?=e(format_date($post['fecha'],true))?></small></div><span class="status-badge <?=$post['status']==='published'?'approved':'pending'?>"><?=e(match($post['status']){'published'=>'Publicada','rejected'=>'Rechazada',default=>'Pendiente'})?></span></div><div class="actions"><?php if($post['status']==='published'):?><a class="button secondary" href="/<?=e($post['slug'])?>">Ver</a><?php endif;?><a class="button warn" href="/community-write.php?id=<?=(int)$post['id']?>">Editar</a><form method="post" action="/community-delete.php" onsubmit="return confirm('¿Eliminar esta publicación?')"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="post_id" value="<?=(int)$post['id']?>"><button class="button danger-bg">Eliminar</button></form></div></article><?php endforeach;?><?php if(!$posts):?><p class="empty">Aún no has publicado ningún tema.</p><?php endif;?></section><?php render_footer();
